#include <stdio.h>

int linearSearch(int arr[], int n, int key) {
    for (int i = 0; i < n; i++) {
        if (arr[i] == key) {
            return i;  // Return index if found
        }
    }
    return -1;  // Return -1 if not found
}

int main() {
    int arr[] = {10, 25, 30, 45, 50, 67};
    int n = sizeof(arr) / sizeof(arr[0]);
    int key = 45;

    int result = linearSearch(arr, n, key);

    if (result != -1)
        printf("Element found at index %d\n", result);
    else
        printf("Element not found in the array\n");

    return 0;
}

public class LinearSearch {

    // Method to perform linear search
    public static int linearSearch(int[] arr, int key) {
        for (int i = 0; i < arr.length; i++) {
            if (arr[i] == key) {
                return i;  // Return index if found
            }
        }
        return -1;  // Return -1 if not found
    }

    public static void main(String[] args) {
        int[] arr = {10, 25, 30, 45, 50, 67};
        int key = 45;

        int result = linearSearch(arr, key);

        if (result != -1) {
            System.out.println("Element found at index " + result);
        } else {
            System.out.println("Element not found in the array");
        }
    }
}

ALGORITHM SentinelLinearSearch(A[0...n-1], key)
// A is the array, key is element to search
BEGIN
    // Save original last element
    lastElement ← A[n-1]

    // Place key at the end as sentinel
    A[n-1] ← key

    // Initialize index
    i ← 0

    // Search until key is found
    WHILE A[i] ≠ key DO
        i ← i + 1
    END WHILE

    // Restore original last element
    A[n-1] ← lastElement

    // Check if found and not at sentinel position
    IF i < n-1 OR A[n-1] = key THEN
        RETURN i
    ELSE
        RETURN -1
    END IF
END
